     1→import type { NullableToPartial } from '../helpers/type-utils';
     2→import type { TSchema } from './lib/type';
     3→
     4→/**
     5→ * Core type definitions and public interfaces for the type validation system.
     6→ */
     7→
     8→export type AllTypes = {
     9→  string: {};
    10→  number: {};
    11→  null: {};
    12→  undefined: {};
    13→  boolean: {};
    14→  unknown: {};
    15→  any: {};
    16→  object: { properties: ObjectTypeProperties };
    17→  enum: { enum: ReadonlyArray<string> };
    18→  list: { items: TypeDefinition };
    19→  union: { union: ReadonlyArray<TypeDefinition> };
    20→  record: { record: TypeDefinition };
    21→  date: {};
    22→  function: {};
    23→  type: { '~typebox': TSchema };
    24→};
    25→
    26→export type ObjectTypeProperties = { [K: string]: TypeDefinition };
    27→
    28→export type TypeName = keyof AllTypes & {};
    29→
    30→/**
    31→ * Type definition using a compact string format.
    32→ * Format: `typeName[?][[]][?]`
    33→ */
    34→export type TypeDefinitionString = `${TypeName}${'?' | ''}${'[]' | ''}${'?' | ''}`;
    35→
    36→/**
    37→ * Type definition using object-based format.
    38→ */
    39→export type ObjectBasedTypeDefinition =
    40→  | AllTypes['object']
    41→  | AllTypes['enum']
    42→  | AllTypes['list']
    43→  | AllTypes['union']
    44→  | AllTypes['record']
    45→  | AllTypes['type'];
    46→
    47→/**
    48→ * Union of all possible type definitions.
    49→ */
    50→export type TypeDefinition = TypeDefinitionString | ObjectBasedTypeDefinition;
    51→
    52→export type FunctionLike = (...params: ReadonlyArray<any>) => any;
    53→
    54→/**
    55→ * Compiled type with validation methods.
    56→ */
    57→export type Type<_Definition extends TypeDefinition = TypeDefinition, Result = unknown> = {
    58→  '~typebox': TSchema;
    59→  list(): Type<any, Result[]>;
    60→  parse<T>(value: T, property?: string): Result;
    61→  parseList<T>(value: T, property?: string): Result[];
    62→  isValid(value: unknown): value is Result;
    63→};
    64→
    65→// Primitive type mapping
    66→type InferPrimitive<T extends string> = T extends 'string'
    67→  ? string
    68→  : T extends 'number'
    69→    ? number
    70→    : T extends 'boolean'
    71→      ? boolean
    72→      : T extends 'null'
    73→        ? null
    74→        : T extends 'undefined'
    75→          ? undefined
    76→          : T extends 'date'
    77→            ? Date
    78→            : T extends 'function'
    79→              ? FunctionLike
    80→              : T extends 'object'
    81→                ? object
    82→                : T extends 'unknown'
    83→                  ? unknown
    84→                  : T extends 'any'
    85→                    ? any
    86→                    : never;
    87→
    88→// Infer from string definition (non-recursive for simple cases)
    89→type InferFromString<T extends string> = T extends `${infer Base}[]?`
