export const GitHubMarketplaceSource = createSchema({
  source: { enum: ['github'] as const },
  repo: 'string',
  ref: 'string?',
  path: 'string?',
});
export type GitHubMarketplaceSource = InferType<typeof GitHubMarketplaceSource>;

/**
 * Generic Git repository marketplace source.
 */
export const GitMarketplaceSource = createSchema({
  source: { enum: ['git'] as const },
  url: 'string',
  ref: 'string?',
  path: 'string?',
});
export type GitMarketplaceSource = InferType<typeof GitMarketplaceSource>;

/**
 * NPM package marketplace source.
 */
export const NpmMarketplaceSource = createSchema({
  source: { enum: ['npm'] as const },
  package: 'string',
});
export type NpmMarketplaceSource = InferType<typeof NpmMarketplaceSource>;

/**
 * Local file marketplace source.
 */
export const FileMarketplaceSource = createSchema({
  source: { enum: ['file'] as const },
  path: 'string',
});
export type FileMarketplaceSource = InferType<typeof FileMarketplaceSource>;

/**
 * Local directory marketplace source.
 */
export const DirectoryMarketplaceSource = createSchema({
  source: { enum: ['directory'] as const },
  path: 'string',
});
export type DirectoryMarketplaceSource = InferType<typeof DirectoryMarketplaceSource>;

/**
 * Union of all marketplace source types.
 */
export const MarketplaceSource = createType({
  union: [
    UrlMarketplaceSource,
    GitHubMarketplaceSource,
    GitMarketplaceSource,
    NpmMarketplaceSource,
    FileMarketplaceSource,
    DirectoryMarketplaceSource,
  ],
});
export type MarketplaceSource = InferType<typeof MarketplaceSource>;

// ============================================================================
// Status Line Types
// ============================================================================

/**
 * Custom status line display configuration.
 */
export const StatusLineConfig = createSchema({
  type: { enum: ['command'] as const },
  command: 'string',
  padding: 'number?',
});
export type StatusLineConfig = InferType<typeof StatusLineConfig>;

// ============================================================================
// Plugin Types
// ============================================================================

/**
 * MCP server configuration value (can be string, number, boolean, or array).
 */
export const McpServerConfigValue = createType({
  union: [
    createType('string'),
    createType('number'),
    createType('boolean'),
    createType({ items: 'string' }),
  ],
});
export type McpServerConfigValue = InferType<typeof McpServerConfigValue>;

/**
 * MCP server configuration map.
 */
export const McpServerConfig = createSchema({
  mcpServers: { record: { record: McpServerConfigValue } },
});
export type McpServerConfig = InferType<typeof McpServerConfig>;

/**
 * Plugin enabled state (boolean or version constraints array).
 */
export const PluginEnabledState = createType({
  union: [createType('boolean'), createType({ items: 'string' })],
});
export type PluginEnabledState = InferType<typeof PluginEnabledState>;

// ============================================================================
// Company Announcement Types
// ============================================================================

/**
 * Company announcement displayed at startup.
 */
export const CompanyAnnouncement = createSchema({
  title: 'string',
  message: 'string',
  priority: 'number?',
  expiresAt: 'string?',
});
export type CompanyAnnouncement = InferType<typeof CompanyAnnouncement>;

// ============================================================================
// Main Settings Schema
// ============================================================================

/**
 * Complete Claude Code settings.json schema.
 *
 * This schema covers all configuration options available in Claude Code,
 * including permissions, hooks, sandbox settings, MCP servers, and more.
 *
 * @example
 * ```typescript
 * const settings = ClaudeCodeSettings.parse({
 *   permissions: {
 *     allow: ['Bash(git:*)', 'Read'],
 *     deny: ['Bash(rm -rf:*)'],
 *     defaultMode: 'default',
 *   },
 *   hooks: {
 *     PreToolUse: [{
 *       matcher: 'Bash',
 *       hooks: [{ type: 'command', command: 'echo "Running bash"' }],
 *     }],
 *   },
 *   cleanupPeriodDays: 30,
 *   includeCoAuthoredBy: true,
 * });
 * ```
 */
export const ClaudeCodeSettings = createSchema({
  // Schema reference
  $schema: 'string?',

  // Authentication & Credentials
  apiKeyHelper: 'string?',
  awsCredentialExport: 'string?',
  awsAuthRefresh: 'string?',
  forceLoginMethod: ForceLoginMethod,
  forceLoginOrgUUID: 'string?',
  otelHeadersHelper: 'string?',

  // Session & Retention
  cleanupPeriodDays: 'number?',
  env: { record: 'string' },

  // Git Integration
  includeCoAuthoredBy: 'boolean?',

  // Permissions
  permissions: PermissionsConfig,

  // Model Configuration
  model: 'string?',
  alwaysThinkingEnabled: 'boolean?',
  outputStyle: 'string?',

  // MCP Server Configuration
  enableAllProjectMcpServers: 'boolean?',
  enabledMcpjsonServers: { items: 'string' },
  disabledMcpjsonServers: { items: 'string' },
  allowedMcpServers: { items: 'string' },
  deniedMcpServers: { items: 'string' },

  // Hooks System
  hooks: HooksConfig,
  disableAllHooks: 'boolean?',

  // Status Line
  statusLine: StatusLineConfig,

  // Plugin System
  enabledPlugins: { record: PluginEnabledState },
  extraKnownMarketplaces: { record: MarketplaceSource },
  skippedMarketplaces: { items: 'string' },
  skippedPlugins: { items: 'string' },
  pluginConfigs: { record: McpServerConfig },

  // Sandbox Configuration
  sandbox: SandboxConfig,

  // UI & Display
  spinnerTipsEnabled: 'boolean?',

  // Network
  skipWebFetchPreflight: 'boolean?',

  // Enterprise
  companyAnnouncements: { items: CompanyAnnouncement },
});

/**
 * Inferred TypeScript type for Claude Code settings.
 */
export type ClaudeCodeSettings = InferType<typeof ClaudeCodeSettings>;

// ============================================================================
// Partial Settings (for merging configurations)
// ============================================================================

/**
 * Partial permissions configuration for incremental updates.
 */
export const PartialPermissionsConfig = createSchema({
  allow: { items: 'string' },
  deny: { items: 'string' },
  ask: { items: 'string' },
  defaultMode: PermissionDefaultMode,
  additionalDirectories: { items: 'string' },
});
export type PartialPermissionsConfig = InferType<typeof PartialPermissionsConfig>;

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Validates a permission rule string format.
 *
 * @example
 * ```typescript
 * isValidPermissionRule('Bash(git:*)'); // true
 * isValidPermissionRule('mcp__automation__*'); // true
 * isValidPermissionRule('InvalidTool'); // false
 * ```
 */
export function isValidPermissionRule(rule: string): boolean {
  const validTools = [
    'Bash',
    'BashOutput',
    'Edit',
    'ExitPlanMode',
    'Glob',
    'Grep',
    'KillShell',
    'NotebookEdit',
    'Read',
    'SlashCommand',
    'Task',
    'TodoWrite',
    'WebFetch',
    'WebSearch',
    'Write',
  ];

  // Check for MCP pattern
  if (rule.startsWith('mcp__')) {
    return true;
  }

  // Check for tool pattern: Tool or Tool(filter)
  const toolMatch = rule.match(/^([A-Za-z]+)(?:\(.*\))?$/);
  if (!toolMatch) {
    return false;
  }

  return validTools.includes(toolMatch[1]);
}

/**
 * Creates a typed permission rule.
 *
 * @example
 * ```typescript
 * const rule = createPermissionRule('Bash', 'git commit:*');
 * // Returns: 'Bash(git commit:*)'
 * ```
 */
export function createPermissionRule(
  tool: string,
  filter?: string,
): string {
  if (filter) {
    return `${tool}(${filter})`;
  }
  return tool;
}

/**
 * Creates a domain-filtered WebFetch permission.
 *
 * @example
 * ```typescript
 * const rule = createWebFetchDomainRule('github.com');
 * // Returns: 'WebFetch(domain:github.com)'
 * ```
 */
export function createWebFetchDomainRule(domain: string): string {
  return `WebFetch(domain:${domain})`;
}

/**
 * Creates a path-filtered permission rule.
 *
 * @example
 * ```typescript
 * const rule = createPathRule('Edit', '/src/**\/*.ts');
 * // Returns: 'Edit(/src/**\/*.ts)'
 * ```
 */
export function createPathRule(tool: 'Edit' | 'Read' | 'Write' | 'Glob', path: string): string {
  return `${tool}(${path})`;
}

// ============================================================================
// Default Configuration Templates
// ============================================================================

/**
 * Default development settings with common permissions.
 */
export const defaultDevelopmentSettings: Partial<ClaudeCodeSettings> = {
  cleanupPeriodDays: 30,
  includeCoAuthoredBy: true,
  spinnerTipsEnabled: true,
  permissions: {
    allow: [
      'Bash(git:*)',
      'Bash(npm:*)',
      'Bash(pnpm:*)',
      'Bash(yarn:*)',
      'Read',
      'Glob',
      'Grep',
    ],
    deny: ['Bash(rm -rf /:*)'],
    defaultMode: 'default',
  },
};

/**
 * Restrictive settings for production environments.
 */
export const restrictiveSettings: Partial<ClaudeCodeSettings> = {
  permissions: {
    allow: ['Read', 'Glob', 'Grep'],
    deny: ['Bash', 'Write', 'Edit'],
    defaultMode: 'plan',
  },
  sandbox: {
    enabled: true,
    network: {
      allowLocalBinding: false,
    },
    autoAllowBashIfSandboxed: false,
    allowUnsandboxedCommands: false,
  },
};

