/**
 * Tests for Claude Code Settings Schema
 *
 * Comprehensive tests demonstrating all schema types and validation.
 */

import { describe, expect, it } from 'vitest';
import {
  ClaudeCodeSettings,
  CommandHook,
  CompanyAnnouncement,
  DirectoryMarketplaceSource,
  FileMarketplaceSource,
  GitHubMarketplaceSource,
  GitMarketplaceSource,
  HookCommand,
  HookMatcher,
  HooksConfig,
  MarketplaceSource,
  McpServerConfig,
  NpmMarketplaceSource,
  PermissionDefaultMode,
  PermissionsConfig,
  PromptHook,
  SandboxConfig,
  SandboxNetworkConfig,
  StatusLineConfig,
  UrlMarketplaceSource,
  createPathRule,
  createPermissionRule,
  createWebFetchDomainRule,
  defaultDevelopmentSettings,
  isValidPermissionRule,
  restrictiveSettings,
} from './claude-code-settings-schema';

// ============================================================================
// Permission Types Tests
// ============================================================================

describe('Permission Types', () => {
  describe('PermissionDefaultMode', () => {
    it('should validate valid default modes', () => {
      expect(PermissionDefaultMode.isValid('acceptEdits')).toBe(true);
      expect(PermissionDefaultMode.isValid('bypassPermissions')).toBe(true);
      expect(PermissionDefaultMode.isValid('default')).toBe(true);
      expect(PermissionDefaultMode.isValid('plan')).toBe(true);
    });

    it('should reject invalid default modes', () => {
      expect(PermissionDefaultMode.isValid('invalid')).toBe(false);
      expect(PermissionDefaultMode.isValid('')).toBe(false);
      expect(PermissionDefaultMode.isValid(123)).toBe(false);
    });

    it('should parse valid mode', () => {
      expect(PermissionDefaultMode.parse('default')).toBe('default');
    });
  });

  describe('PermissionsConfig', () => {
    it('should validate complete permissions config', () => {
      const config = {
        allow: ['Bash(git:*)', 'Read', 'Glob'],
        deny: ['Bash(rm -rf:*)'],
        ask: ['Write'],
        defaultMode: 'default',
        additionalDirectories: ['/home/user/projects'],
      };

      expect(PermissionsConfig.isValid(config)).toBe(true);
    });

    it('should parse permissions config', () => {
      const config = {
        allow: ['Read'],
        deny: [],
        defaultMode: 'plan',
      };

      const parsed = PermissionsConfig.parse(config);
      expect(parsed.allow).toEqual(['Read']);
      expect(parsed.defaultMode).toBe('plan');
    });
  });
});

// ============================================================================
// Hook Types Tests
// ============================================================================

describe('Hook Types', () => {
  describe('CommandHook', () => {
    it('should validate command hook', () => {
      const hook = {
        type: 'command',
        command: 'echo "hello"',
      };
      expect(CommandHook.isValid(hook)).toBe(true);
    });

    it('should validate command hook with timeout', () => {
      const hook = {
        type: 'command',
        command: './scripts/pre-commit.sh',
        timeout: 30,
      };
      expect(CommandHook.isValid(hook)).toBe(true);
    });

    it('should reject invalid command hook', () => {
      expect(CommandHook.isValid({ type: 'prompt', command: 'test' })).toBe(false);
      expect(CommandHook.isValid({ type: 'command' })).toBe(false);
    });
  });

  describe('PromptHook', () => {
    it('should validate prompt hook', () => {
      const hook = {
        type: 'prompt',
        prompt: 'Check the code for security issues: $ARGUMENTS',
      };
      expect(PromptHook.isValid(hook)).toBe(true);
    });

    it('should validate prompt hook with timeout', () => {
      const hook = {
        type: 'prompt',
        prompt: 'Review this change',
        timeout: 60,
      };
      expect(PromptHook.isValid(hook)).toBe(true);
    });
  });

  describe('HookCommand', () => {
    it('should validate command type', () => {
      expect(
        HookCommand.isValid({ type: 'command', command: 'test' }),
      ).toBe(true);
    });

    it('should validate prompt type', () => {
      expect(
        HookCommand.isValid({ type: 'prompt', prompt: 'test' }),
      ).toBe(true);
    });
  });

  describe('HookMatcher', () => {
    it('should validate hook matcher without matcher pattern', () => {
      const matcher = {
        hooks: [{ type: 'command', command: 'echo "hook"' }],
      };
      expect(HookMatcher.isValid(matcher)).toBe(true);
    });

    it('should validate hook matcher with matcher pattern', () => {
      const matcher = {
        matcher: 'Bash',
        hooks: [
          { type: 'command', command: 'echo "pre-bash"' },
          { type: 'prompt', prompt: 'Check command safety' },
        ],
      };
      expect(HookMatcher.isValid(matcher)).toBe(true);
    });
  });

  describe('HooksConfig', () => {
    it('should validate complete hooks config', () => {
      const config = {
        PreToolUse: [
          {
            matcher: 'Bash',
            hooks: [{ type: 'command', command: 'echo "pre"' }],
          },
        ],
        PostToolUse: [
          {
            hooks: [{ type: 'prompt', prompt: 'Verify result' }],
          },
        ],
        SessionStart: [
          {
            hooks: [{ type: 'command', command: './init.sh' }],
          },
        ],
      };
      expect(HooksConfig.isValid(config)).toBe(true);
    });
  });
});

// ============================================================================
// Sandbox Types Tests
// ============================================================================

describe('Sandbox Types', () => {
  describe('SandboxNetworkConfig', () => {
    it('should validate network config', () => {
      const config = {
        allowUnixSockets: ['/var/run/docker.sock'],
        allowLocalBinding: true,
        httpProxyPort: 8080,
        socksProxyPort: 1080,
      };
      expect(SandboxNetworkConfig.isValid(config)).toBe(true);
    });

    it('should validate partial network config', () => {
      const config = {
        allowLocalBinding: false,
      };
      expect(SandboxNetworkConfig.isValid(config)).toBe(true);
    });
  });

  describe('SandboxConfig', () => {
    it('should validate complete sandbox config', () => {
      const config = {
        network: {
          allowUnixSockets: [],
          allowLocalBinding: false,
        },
        ignoreViolations: {
          docker: ['/var/run/docker.sock'],
        },
        excludedCommands: ['docker', 'kubectl'],
        autoAllowBashIfSandboxed: true,
        enableWeakerNestedSandbox: false,
        allowUnsandboxedCommands: false,
        enabled: true,
      };
      expect(SandboxConfig.isValid(config)).toBe(true);
    });
  });
});

// ============================================================================
// Marketplace Source Types Tests
// ============================================================================

describe('Marketplace Source Types', () => {
  describe('UrlMarketplaceSource', () => {
    it('should validate URL source', () => {
      const source = {
        source: 'url',
        url: 'https://example.com/marketplace.json',
      };
      expect(UrlMarketplaceSource.isValid(source)).toBe(true);
    });
  });

  describe('GitHubMarketplaceSource', () => {
    it('should validate GitHub source', () => {
      const source = {
        source: 'github',
        repo: 'anthropics/claude-plugins',
        ref: 'main',
        path: '.claude-plugin/marketplace.json',
      };
      expect(GitHubMarketplaceSource.isValid(source)).toBe(true);
    });

    it('should validate GitHub source without optional fields', () => {
      const source = {
        source: 'github',
        repo: 'owner/repo',
      };
      expect(GitHubMarketplaceSource.isValid(source)).toBe(true);
    });
  });

  describe('GitMarketplaceSource', () => {
    it('should validate Git source', () => {
      const source = {
        source: 'git',
        url: 'https://gitlab.com/org/repo.git',
        ref: 'v1.0.0',
      };
      expect(GitMarketplaceSource.isValid(source)).toBe(true);
    });
  });

  describe('NpmMarketplaceSource', () => {
    it('should validate NPM source', () => {
      const source = {
        source: 'npm',
        package: '@anthropic/claude-plugins',
      };
      expect(NpmMarketplaceSource.isValid(source)).toBe(true);
    });
  });

  describe('FileMarketplaceSource', () => {
    it('should validate file source', () => {
      const source = {
        source: 'file',
        path: '/home/user/.claude/marketplace.json',
      };
      expect(FileMarketplaceSource.isValid(source)).toBe(true);
    });
  });

  describe('DirectoryMarketplaceSource', () => {
    it('should validate directory source', () => {
      const source = {
        source: 'directory',
        path: '/home/user/.claude/plugins',
      };
      expect(DirectoryMarketplaceSource.isValid(source)).toBe(true);
    });
  });

  describe('MarketplaceSource (union)', () => {
    it('should validate any marketplace source type', () => {
      expect(MarketplaceSource.isValid({ source: 'url', url: 'https://example.com' })).toBe(true);
      expect(MarketplaceSource.isValid({ source: 'github', repo: 'owner/repo' })).toBe(true);
      expect(MarketplaceSource.isValid({ source: 'npm', package: 'pkg' })).toBe(true);
      expect(MarketplaceSource.isValid({ source: 'file', path: '/path' })).toBe(true);
      expect(MarketplaceSource.isValid({ source: 'directory', path: '/dir' })).toBe(true);
    });

    it('should reject invalid source', () => {
      expect(MarketplaceSource.isValid({ source: 'invalid', data: 'test' })).toBe(false);
    });
  });
});

// ============================================================================
// Status Line Tests
// ============================================================================

describe('StatusLineConfig', () => {
  it('should validate status line config', () => {
    const config = {
      type: 'command',
      command: './scripts/status.sh',
      padding: 2,
    };
    expect(StatusLineConfig.isValid(config)).toBe(true);
  });

  it('should validate status line without padding', () => {
    const config = {
      type: 'command',
      command: 'echo "status"',
    };
    expect(StatusLineConfig.isValid(config)).toBe(true);
  });
});

// ============================================================================
// Plugin Types Tests
// ============================================================================

describe('Plugin Types', () => {
  describe('McpServerConfig', () => {
    it('should validate MCP server config', () => {
      const config = {
        mcpServers: {
          'my-server': {
            apiKey: 'secret',
            port: 8080,
            enabled: true,
            hosts: ['localhost', '127.0.0.1'],
          },
        },
      };
      expect(McpServerConfig.isValid(config)).toBe(true);
    });
  });
});

// ============================================================================
// Company Announcement Tests
// ============================================================================

describe('CompanyAnnouncement', () => {
  it('should validate announcement', () => {
    const announcement = {
      title: 'Welcome',
      message: 'Welcome to Claude Code!',
    };
    expect(CompanyAnnouncement.isValid(announcement)).toBe(true);
  });

  it('should validate announcement with optional fields', () => {
    const announcement = {
      title: 'Maintenance',
      message: 'Scheduled maintenance tonight',
      priority: 1,
      expiresAt: '2025-12-31T23:59:59Z',
    };
    expect(CompanyAnnouncement.isValid(announcement)).toBe(true);
  });
});

// ============================================================================
// Main Settings Schema Tests
// ============================================================================

describe('ClaudeCodeSettings', () => {
  it('should validate minimal settings', () => {
    const settings = {};
    expect(ClaudeCodeSettings.isValid(settings)).toBe(true);
  });

  it('should validate settings with schema reference', () => {
    const settings = {
      $schema: 'https://json.schemastore.org/claude-code-settings.json',
    };
    expect(ClaudeCodeSettings.isValid(settings)).toBe(true);
  });

  it('should validate authentication settings', () => {
    const settings = {
      apiKeyHelper: './scripts/get-api-key.sh',
      awsCredentialExport: './scripts/aws-creds.sh',
      awsAuthRefresh: './scripts/aws-refresh.sh',
      forceLoginMethod: 'claudeai',
      forceLoginOrgUUID: 'org-uuid-123',
    };
    expect(ClaudeCodeSettings.isValid(settings)).toBe(true);
  });

  it('should validate session settings', () => {
    const settings = {
      cleanupPeriodDays: 7,
      env: {
        NODE_ENV: 'development',
        DEBUG: 'true',
      },
    };
    expect(ClaudeCodeSettings.isValid(settings)).toBe(true);
  });

  it('should validate model settings', () => {
    const settings = {
      model: 'claude-3-opus',
      alwaysThinkingEnabled: true,
      outputStyle: 'Explanatory',
    };
    expect(ClaudeCodeSettings.isValid(settings)).toBe(true);
  });

  it('should validate MCP server settings', () => {
    const settings = {
      enableAllProjectMcpServers: true,
      enabledMcpjsonServers: ['server1', 'server2'],
      disabledMcpjsonServers: ['server3'],
      allowedMcpServers: ['approved-server'],
      deniedMcpServers: ['blocked-server'],
    };
    expect(ClaudeCodeSettings.isValid(settings)).toBe(true);
  });

  it('should validate complete settings', () => {
    const settings = {
      $schema: 'https://json.schemastore.org/claude-code-settings.json',
      cleanupPeriodDays: 30,
      includeCoAuthoredBy: true,
      permissions: {
        allow: ['Bash(git:*)', 'Read', 'Glob', 'Grep'],
        deny: ['Bash(rm -rf /:*)'],
        ask: ['Write', 'Edit'],
        defaultMode: 'default',
        additionalDirectories: ['/home/user/shared'],
      },
      hooks: {
        PreToolUse: [
          {
            matcher: 'Bash',
            hooks: [{ type: 'command', command: 'echo "pre-bash"' }],
          },
        ],
        SessionStart: [
          {
            hooks: [{ type: 'command', command: './scripts/init.sh' }],
          },
        ],
      },
      sandbox: {
        enabled: true,
        network: {
          allowLocalBinding: true,
          httpProxyPort: 8080,
        },
        excludedCommands: ['docker'],
      },
      statusLine: {
        type: 'command',
        command: './scripts/status.sh',
      },
      spinnerTipsEnabled: true,
      model: 'claude-3-opus',
      env: {
        NODE_ENV: 'development',
      },
    };

    expect(ClaudeCodeSettings.isValid(settings)).toBe(true);

    const parsed = ClaudeCodeSettings.parse(settings);
    expect(parsed.cleanupPeriodDays).toBe(30);
    expect(parsed.permissions?.allow).toContain('Read');
    expect(parsed.sandbox?.enabled).toBe(true);
  });
});

// ============================================================================
// Helper Functions Tests
// ============================================================================

describe('Helper Functions', () => {
  describe('isValidPermissionRule', () => {
    it('should validate standard tool rules', () => {
      expect(isValidPermissionRule('Bash')).toBe(true);
      expect(isValidPermissionRule('Read')).toBe(true);
      expect(isValidPermissionRule('Write')).toBe(true);
      expect(isValidPermissionRule('Edit')).toBe(true);
      expect(isValidPermissionRule('Glob')).toBe(true);
      expect(isValidPermissionRule('Grep')).toBe(true);
      expect(isValidPermissionRule('Task')).toBe(true);
      expect(isValidPermissionRule('WebFetch')).toBe(true);
      expect(isValidPermissionRule('WebSearch')).toBe(true);
    });

    it('should validate tool rules with filters', () => {
      expect(isValidPermissionRule('Bash(git:*)')).toBe(true);
      expect(isValidPermissionRule('Bash(npm install:*)')).toBe(true);
      expect(isValidPermissionRule('Edit(/src/**/*.ts)')).toBe(true);
      expect(isValidPermissionRule('Read(*.env)')).toBe(true);
      expect(isValidPermissionRule('WebFetch(domain:github.com)')).toBe(true);
    });

    it('should validate MCP rules', () => {
      expect(isValidPermissionRule('mcp__automation__*')).toBe(true);
      expect(isValidPermissionRule('mcp__playwright__browser_click')).toBe(true);
    });

    it('should reject invalid rules', () => {
      expect(isValidPermissionRule('InvalidTool')).toBe(false);
      expect(isValidPermissionRule('')).toBe(false);
      expect(isValidPermissionRule('123')).toBe(false);
    });
  });

  describe('createPermissionRule', () => {
    it('should create rule without filter', () => {
      expect(createPermissionRule('Read')).toBe('Read');
    });

    it('should create rule with filter', () => {
      expect(createPermissionRule('Bash', 'git:*')).toBe('Bash(git:*)');
      expect(createPermissionRule('Edit', '/src/**/*.ts')).toBe('Edit(/src/**/*.ts)');
    });
  });

  describe('createWebFetchDomainRule', () => {
    it('should create domain-filtered WebFetch rule', () => {
      expect(createWebFetchDomainRule('github.com')).toBe('WebFetch(domain:github.com)');
      expect(createWebFetchDomainRule('api.anthropic.com')).toBe(
        'WebFetch(domain:api.anthropic.com)',
      );
    });
  });

